import * as aws from 'aws-sdk'
const sqs = new aws.SQS({
  apiVersion: '2012-11-05',
})
let queueUrl = '<queue url goes here>' // your SQS queue URL goes here
async function run() {

  const getParams =  {
    QueueUrl: queueUrl, 
    AttributeNames : ['All'], 
    MaxNumberOfMessages: 10
  }

  try {

    console.log('Starting')
    let response = await sqs.receiveMessage(getParams).promise()
    
    if (response.hasOwnProperty('Messages')) {

      // for each message
      for (let message of response['Messages']) {
        
        const deleteParams = {
          QueueUrl: queueUrl, 
          ReceiptHandle: message.ReceiptHandle
        }

        let delete_response = await sqs.deleteMessage(deleteParams).promise()
        console.log('Deleting Message', delete_params)
        
      }
    }
  } catch (e) {
    throw new Error(`SQS ERROR: ${e}`)
  }
}
